import{_ as a,a as t,b as o,c as r,d as i,e as n}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as l,c as d,a2 as p}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Ajouter un canal Dropbox","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/upload/dropbox.md","filePath":"fr-FR/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"fr-FR/upload/dropbox.md"};function u(h,e,b,m,g,x){return l(),d("div",null,[...e[0]||(e[0]=[p('<h1 id="ajouter-un-canal-dropbox" tabindex="-1">Ajouter un canal Dropbox <a class="header-anchor" href="#ajouter-un-canal-dropbox" aria-label="Permalink to &quot;Ajouter un canal Dropbox&quot;">​</a></h1><p>Le canal Dropbox utilise un compte Dropbox comme destination de stockage.</p><h2 id="a-preparer" tabindex="-1">À préparer <a class="header-anchor" href="#a-preparer" aria-label="Permalink to &quot;À préparer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Élément</th><th>Utilité</th></tr></thead><tbody><tr><td>Compte Dropbox</td><td>Enregistrer les fichiers</td></tr><tr><td>Dropbox App</td><td>Donner un accès API</td></tr><tr><td>Access Token</td><td>Autoriser ImgBed à utiliser Dropbox</td></tr><tr><td>Dossier</td><td>Optionnel, souvent <code>imgbed</code></td></tr></tbody></table><h2 id="creer-l-application" tabindex="-1">Créer l’application <a class="header-anchor" href="#creer-l-application" aria-label="Permalink to &quot;Créer l’application&quot;">​</a></h2><p>Ouvrez Dropbox App Console et créez une application.</p><p><img src="'+a+'" alt="Créer l’application" loading="lazy"></p><p>Choisissez le périmètre selon votre organisation de stockage. Un dossier dédié est souvent plus facile à maintenir.</p><h2 id="configurer-le-callback" tabindex="-1">Configurer le callback <a class="header-anchor" href="#configurer-le-callback" aria-label="Permalink to &quot;Configurer le callback&quot;">​</a></h2><p>Si vous utilisez OAuth, ajoutez l’URL de retour ImgBed :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://votre-domaine/api/oauth/dropbox/callback</span></span></code></pre></div><p><img src="'+t+'" alt="Configurer le callback" loading="lazy"></p><h2 id="ajouter-les-permissions" tabindex="-1">Ajouter les permissions <a class="header-anchor" href="#ajouter-les-permissions" aria-label="Permalink to &quot;Ajouter les permissions&quot;">​</a></h2><p>Activez les permissions d’envoi, lecture et suppression nécessaires.</p><p><img src="'+o+'" alt="Permissions Dropbox" loading="lazy"></p><h2 id="obtenir-le-token" tabindex="-1">Obtenir le token <a class="header-anchor" href="#obtenir-le-token" aria-label="Permalink to &quot;Obtenir le token&quot;">​</a></h2><p>Obtenez le token depuis l’application ou via le flux d’autorisation ImgBed.</p><p><img src="'+r+'" alt="Obtenir le token" loading="lazy"></p><p>Copiez le token et collez-le dans ImgBed.</p><p><img src="'+i+'" alt="Copier le token" loading="lazy"></p><h2 id="renseigner-dans-imgbed" tabindex="-1">Renseigner dans ImgBed <a class="header-anchor" href="#renseigner-dans-imgbed" aria-label="Permalink to &quot;Renseigner dans ImgBed&quot;">​</a></h2><p>Dans Paramètres d’upload, choisissez <code>Dropbox</code>.</p><table tabindex="0"><thead><tr><th>Champ</th><th>Valeur</th></tr></thead><tbody><tr><td>Nom du canal</td><td>Nom reconnaissable</td></tr><tr><td>Access Token</td><td>Token Dropbox</td></tr><tr><td>Dossier</td><td>Optionnel ; vide ou <code>imgbed</code></td></tr><tr><td>Note</td><td>Optionnel</td></tr></tbody></table><h2 id="verification" tabindex="-1">Vérification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Vérification&quot;">​</a></h2><p>Après enregistrement, lancez une consultation de capacité ou envoyez une image de test.</p><p><img src="'+n+'" alt="Consultation de capacité" loading="lazy"></p><p>Si le fichier apparaît dans Dropbox et que le lien ImgBed s’ouvre, le canal est prêt.</p><h2 id="en-cas-d-echec" tabindex="-1">En cas d’échec <a class="header-anchor" href="#en-cas-d-echec" aria-label="Permalink to &quot;En cas d’échec&quot;">​</a></h2><ul><li>Token expiré ou permissions incomplètes.</li><li>Permissions de l’application changées sans nouvelle autorisation.</li><li>Dossier avec espaces ou barres inutiles.</li><li>Espace Dropbox insuffisant.</li></ul>',29)])])}const v=s(c,[["render",u]]);export{_ as __pageData,v as default};
